import React, { useState } from "react";
import { XMarkIcon } from "@heroicons/react/24/solid";
import UserRegister from "./userRegister";
import FloatingInput from "../component/FloatingInput";
import { useNavigate } from "react-router-dom";

export default function Login({ closeModal }) {
  const [formData, setFormData] = useState({
    username: "",
    password: "",
  });

  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");
  const [showRegister, setShowRegister] = useState(false);

  const navigate = useNavigate();
  const BASE_URL = "http://localhost:8086";

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
    setError("");
    setSuccess("");
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    if (!formData.username || !formData.password) {
      setError("All fields are required");
      return;
    }

    try {
      const response = await fetch(`${BASE_URL}/user/login`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          login: formData.username,
          password: formData.password,
        }),
      });

      const data = await response.json();

      if (!response.ok) {
        setError(data?.message || "Invalid credentials");
        return;
      }

      const userData = {
        username: data.username,
        email: data.email,
        role: data.role,
        profileImage: data.profileImage || null,
        token: data.token || null,
      };

      localStorage.setItem("user", JSON.stringify(userData));
      localStorage.setItem("role", userData.role);

      setSuccess("Login successful!");

      setTimeout(() => {
        closeModal?.();
        navigate("/dashboard");
      }, 600);

    } catch {
      setError("Server connection failed");
    }
  };

  return (
    <div className="fixed inset-0 flex items-center justify-center z-[9999]">
      <div className="absolute inset-0 backdrop-blur-sm" onClick={closeModal} />

      <div className="relative w-[500px] p-8 rounded-2xl backdrop-blur-xl bg-white/20 border border-white/30 shadow-2xl">

        <button onClick={closeModal} className="absolute top-3 right-3 text-white">
          <XMarkIcon className="w-6 h-6" />
        </button>

        <h2 className="text-2xl font-bold text-white text-center mb-6">Login</h2>

        {success && <p className="text-green-300 text-center">{success}</p>}
        {error && <p className="text-red-300 text-center">{error}</p>}

        <form onSubmit={handleSubmit} className="space-y-4">
          <FloatingInput
            name="username"
            label="Username or Email"
            value={formData.username}
            onChange={handleChange}
          />

          <FloatingInput
            name="password"
            type="password"
            label="Password"
            value={formData.password}
            onChange={handleChange}
          />

          <button className="w-full py-2 rounded-lg bg-white/30 text-white">
            Login
          </button>
        </form>

        <p className="text-center text-white/80 mt-4">
          Don't have an account?{" "}
          <span onClick={() => setShowRegister(true)} className="text-sky-400 cursor-pointer">
            Register
          </span>
        </p>
      </div>

      {showRegister && (
        <div className="fixed inset-0 flex items-center justify-center z-[9999]">
          <div className="absolute inset-0 bg-black/40" onClick={() => setShowRegister(false)} />
          <UserRegister closeModal={() => setShowRegister(false)} />
        </div>
      )}
    </div>
  );
}
